mapper.select:
SELECT industry_name, industry_code, workplace_name, sido_code as sido_name, sigungu_code as sigungu_name, member_count, business_registration_number FROM datacollection_national_pension WHERE workplace_status_code = '1' AND industry_name IN
#{name}
ORDER BY industry_name, member_count DESC

SELECT industry_name, sido_code, COUNT(*) as workplace_count, SUM(member_count) as total_members, AVG(member_count) as avg_members FROM datacollection_national_pension WHERE workplace_status_code = '1' AND industry_name IS NOT NULL AND industry_name != 'BIZ_NO미존재사업장' AND industry_name != '해당없음'
AND sido_code = #{sidoCode}
GROUP BY industry_name, sido_code HAVING COUNT(*) >= 5 -- 최소 5개 사업장 ORDER BY total_members DESC
